#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt;
}e[20010];
long long head[20010],tot=1;
long long n,m,s,t,d[20010],now[20010];
void add1(long long u,long long v,long long w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(long long i=0;i<=t;i++)
    {
        d[i]=0;
    }
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,2e9);
    }
    return ans;
}
vector<int> ans[1010];
int main()
{
    long long k;
    scanf("%lld%lld",&k,&n);
    s=n+k+1;
    t=s+1;
    long long sum=0;
    for(long long i=1;i<=k;i++)
    {
        long long x;
        scanf("%lld",&x);
        sum+=x;
        add(i+n,t,x);
    }
    for(long long i=1;i<=n;i++)
    {
        add(s,i,1);
        long long c;
        scanf("%lld",&c);
        while(c--)
        {
            long long x;
            scanf("%lld",&x);
            add(i,x+n,1);
        }
    }
    if(dinic()==sum)
    {
        for(int i=1;i<=k;i++)
        {
            for(int j=head[i+n];j;j=e[j].nxt)
            {
                int v=e[j].to;
                if(v<=n&&e[j].val)
                {
                    ans[i].push_back(v);
                }
            }
        }
        for(int i=1;i<=k;i++)
        {
            printf("%d: ",i);
            for(int j:ans[i])
            {
                printf("%d ",j);
            }
            printf("\n");
        }
    }
    else
    {
        printf("No Solution!");
    }
    return 0;
}
